sql:
SELECT region_id
FROM region_statistics
WHERE avg_box_office = (SELECT MAX(avg_box_office) FROM region_statistics);

SELECT total_offices, avg_box_office
FROM country_statistics
WHERE country_id = 0;

SELECT AVG(box_office) AS average_box_office
FROM offices
WHERE country_id = 1;

SELECT countries.country_name, offices.box_office
FROM countries
INNER JOIN offices ON countries.country_id = offices.country_id;

SELECT region_id, total_offices, avg_box_office
FROM region_statistics
WHERE avg_box_office > 25;

external_knowledge:
- Major revenue-generating offices refer to those with a box office value over $100,000,000;
- The term 'top three' here pertains to the ranking based on office IDs, meaning the three earliest (numerically smallest) office IDs;
- 'Manager-country combination' indicates the pairing of a specific manager and a country.

sql:
SELECT countries.country_name
FROM demographic_data
JOIN countries ON demographic_data.country_id = countries.country_id;

SELECT SUM(box_office) AS total_box_office
FROM offices
WHERE country_id = 1;

SELECT c.country_name
FROM offices o
JOIN countries c ON o.country_id = c.country_id
WHERE o.box_office = (
    SELECT MAX(box_office) FROM offices
);

SELECT country_id, avg_office_density 
FROM country_office_density
WHERE avg_office_density > 1.5;

SELECT country_id, office_count, avg_office_density
FROM office_density
WHERE population_density > 1000;
